# Module defining base shapes and interfaces

interface IDrawable:
    def draw() -> str
    ...

interface IMeasurable:
    def circumference() -> float
    ...

# Base shape class
class Shape:
    name: str
    x: int
    y: int

    def __init__(self, name: str, x: int, y: int):
        self.name = name
        self.x = x
        self.y = y

    @virtual
    def area(self) -> float:
        return 0.0

    @virtual
    def describe(self) -> str:
        return f"Shape {{self.name}} at ({{self.x}}, {{self.y}})"

class Circle(Shape, IDrawable, IMeasurable):
    radius: float

    def __init__(self, x: int, y: int, radius: float):
        super().__init__("circle", x, y)
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def describe(self) -> str:
        return f"Circle radius={{self.radius}} at ({{self.x}}, {{self.y}})"

    def circumference(self) -> float:
        return 2.0 * 3.14159 * self.radius

    def draw(self) -> str:
        return f"Drawing circle with radius {{self.radius}}"

class Rectangle(Shape, IDrawable, IMeasurable):
    width: float
    height: float

    def __init__(self, x: int, y: int, width: float, height: float):
        super().__init__("rectangle", x, y)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def describe(self) -> str:
        return f"Rectangle {{self.width}}x{{self.height}} at ({{self.x}}, {{self.y}})"

    def circumference(self) -> float:
        return 2.0 * (self.width + self.height)

    def draw(self) -> str:
        return f"Drawing rectangle {{self.width}}x{{self.height}}"

