# Module that uses shapes and extends functionality
from shapes import Shape, Circle, Rectangle, IDrawable, IMeasurable

class Triangle(Shape, IDrawable):
    base: float
    triangle_height: float

    def __init__(self, x: int, y: int, base: float, height: float):
        super().__init__("triangle", x, y)
        self.base = base
        self.triangle_height = height

    @override
    def area(self) -> float:
        return 0.5 * self.base * self.triangle_height

    @override
    def describe(self) -> str:
        return f"Triangle base={{self.base}} height={{self.triangle_height}}"

    def draw(self) -> str:
        return f"Drawing triangle with base {{self.base}}"

class Canvas:
    shapes: list[Shape]

    def __init__(self):
        self.shapes = []

    def add(self, shape: Shape):
        self.shapes.append(shape)

    def total_area(self) -> float:
        total: float = 0.0
        for shape in self.shapes:
            total = total + shape.area()
        return total

    def draw_all(self) -> list[str]:
        drawings: list[str] = []
        for shape in self.shapes:
            # Check if shape implements IDrawable
            if isinstance(shape, IDrawable):
                drawable: IDrawable = shape
                drawings.append(drawable.draw())
        return drawings

def scale_shape(shape: Shape, factor: float) -> Shape:
    return shape

def describe_shapes(shapes: list[Shape]) -> list[str]:
    descriptions: list[str] = []
    for shape in shapes:
        descriptions.append(shape.describe())
    return descriptions
